operation.add:
// EasyCheckout (oc-kit) — додатковий таб з custom-полями замовлення
if ($this->user->hasPermission('access', 'extension/module/oc_kit_easycheckout')) {
    $this->load->model('extension/module/oc_kit_easycheckout');
    if (method_exists($this->model_extension_module_oc_kit_easycheckout, 'renderOrderCustomFieldsHtml')) {
        $okec_html = $this->model_extension_module_oc_kit_easycheckout->renderOrderCustomFieldsHtml((int)$order_info['order_id']);
        if ($okec_html) {
            $data['tabs'][] = [
                'code'    => 'oc_kit_easycheckout',
                'title'   => 'EasyCheckout',
                'content' => $okec_html,
            ];
        }
    }
}
